15	import org.springframework.http.MediaType;
16	import org.springframework.http.ResponseEntity;
17	import org.springframework.security.access.prepost.PreAuthorize;
18	import org.springframework.web.bind.annotation.GetMapping;
19	import org.springframework.web.bind.annotation.PathVariable;
20	import org.springframework.web.bind.annotation.PostMapping;
21	import org.springframework.web.bind.annotation.PutMapping;
22	import org.springframework.web.bind.annotation.RequestBody;
23	import org.springframework.web.bind.annotation.RequestMapping;
24	import org.springframework.web.bind.annotation.RequestParam;
25	import org.springframework.web.bind.annotation.RestController;
26	import org.springframework.web.multipart.MultipartFile;
27	
28	import java.io.IOException;
29	import java.nio.charset.StandardCharsets;
30	
31	/**
32	 * /api/students — list, CRUD, and CSV bulk import. All endpoints are gated by
33	 * permission code; the service additionally enforces the data-scope filter.
34	 */
35	@RestController
36	@RequestMapping("/api/students")
37	public class StudentController {
38	
39	    private final StudentService studentService;
40	
41	    public StudentController(StudentService studentService) {
42	        this.studentService = studentService;
43	    }
44	
45	    @GetMapping
46	    @PreAuthorize("hasAuthority('students.read')")
47	    public ApiResponse<Page<StudentResponse>> list(Pageable pageable) {
48	        return ApiResponse.ok(studentService.list(pageable));
49	    }
50	
51	    @GetMapping("/{id}")
52	    @PreAuthorize("hasAuthority('students.read')")
53	    public ApiResponse<StudentResponse> get(@PathVariable Long id) {
54	        return ApiResponse.ok(studentService.get(id));
55	    }
56	
57	    @PostMapping
58	    @PreAuthorize("hasAuthority('students.write')")
59	    public ApiResponse<StudentResponse> create(@Valid @RequestBody CreateStudentRequest req,
60	                                               HttpServletRequest httpReq) {
61	        return ApiResponse.ok(studentService.create(req, clientIp(httpReq)));
62	    }
63	
64	    @PutMapping("/{id}")
65	    @PreAuthorize("hasAuthority('students.write')")
66	    public ApiResponse<StudentResponse> update(@PathVariable Long id,
67	                                               @Valid @RequestBody UpdateStudentRequest req,
68	                                               HttpServletRequest httpReq) {
69	        return ApiResponse.ok(studentService.update(id, req, clientIp(httpReq)));
70	    }
71	
72	    @PostMapping("/import")
73	    @PreAuthorize("hasAuthority('students.import')")
74	    public ApiResponse<BulkImportResult> importCsv(
75	            @RequestParam("organizationId") Long organizationId,
76	            @RequestParam("file") MultipartFile file,
77	            HttpServletRequest httpReq) {
78	        if (file == null || file.isEmpty()) {
79	            throw new BusinessException("EMPTY_FILE", "CSV file is required",
80	                    HttpStatus.BAD_REQUEST);
81	        }
82	        try {
83	            return ApiResponse.ok(studentService.importCsv(
84	                    organizationId, file.getInputStream(), clientIp(httpReq)));
85	        } catch (IOException ioe) {
86	            throw new BusinessException("CSV_READ_FAILED",
87	                    "Could not read upload: " + ioe.getMessage(), HttpStatus.BAD_REQUEST);
88	        }
89	    }
90	
91	    /**
92	     * Download the CSV template for student bulk imports. Served as a raw
93	     * text/csv so the client browser saves it with a {@code .csv} extension
94	     * directly. Gated on the import permission so non-importers can't probe
95	     * the expected header shape.
96	     */
97	    @GetMapping(value = "/import/template", produces = "text/csv")
98	    @PreAuthorize("hasAuthority('students.import')")
99	    public ResponseEntity<byte[]> importTemplate() {
100	        byte[] body = studentService.buildImportTemplate().getBytes(StandardCharsets.UTF_8);
101	        return ResponseEntity.ok()
102	                .contentType(MediaType.parseMediaType("text/csv"))
103	                .header(HttpHeaders.CONTENT_DISPOSITION,
104	                        "attachment; filename=\"student-import-template.csv\"")
105	                .body(body);
106	    }
107	
108	    /**
109	     * Download the complete error report for a finished import job. The body
110	     * is the same error rows the service wrote to disk during the import run;
111	     * the sample embedded in the import response is capped at 20 rows.
112	     */
113	    @GetMapping(value = "/import/{jobId}/errors", produces = "text/csv")
114	    @PreAuthorize("hasAuthority('students.import')")
115	    public ResponseEntity<byte[]> importErrors(@PathVariable Long jobId) {
116	        byte[] body = studentService.readErrorReport(jobId);
117	        return ResponseEntity.ok()
118	                .contentType(MediaType.parseMediaType("text/csv"))
119	                .header(HttpHeaders.CONTENT_DISPOSITION,
120	                        "attachment; filename=\"student-import-" + jobId + "-errors.csv\"")
121	                .body(body);
122	    }
123	
124	    private static String clientIp(HttpServletRequest req) {
125	        String xff = req.getHeader("X-Forwarded-For");
126	        if (xff != null && !xff.isBlank()) {
127	            int comma = xff.indexOf(',');
128	            return comma > 0 ? xff.substring(0, comma).trim() : xff.trim();
129	        }
130	        return req.getRemoteAddr();
131	    }
132	}
