37	/**
38	 * Idempotent bootstrap data: base resources, permissions, roles, org structure, and
39	 * default users. Phase 2 adds the organization/department/facility area sample data
40	 * and a scoped staff user so the data-scope filter can be exercised locally.
41	 *
42	 * <p>Runs on application start when {@code dojostay.bootstrap.seed-on-start=true}.
43	 * Each entity is created only if missing, so this is safe to keep enabled across
44	 * restarts. The default admin and sample staff passwords are read from configuration;
45	 * if a password is missing the corresponding user is simply not created rather than
46	 * falling back to an embedded default.
47	 */
48	@Configuration
49	@EnableConfigurationProperties(BootstrapProperties.class)
50	public class DataSeeder {
51	
52	    private static final Logger log = LoggerFactory.getLogger(DataSeeder.class);
53	
54	    /**
55	     * Resource buckets used to group permissions in admin UIs. Adding a new
56	     * resource here is all that is required — no migration needed because the
57	     * link from permissions to resources is a soft reference on the code.
58	     */
