103	            new PermissionSeed("training.write", "Create or modify training offerings", "training"),
104	            new PermissionSeed("bookings.read", "View bookings", "bookings"),
105	            new PermissionSeed("bookings.write", "Create or cancel bookings", "bookings"),
106	            new PermissionSeed("credits.read", "View student credit balances", "credits"),
107	            new PermissionSeed("credits.write", "Grant or consume student credits", "credits"),
108	            // Phase 6
109	            new PermissionSeed("community.read", "View community content", "community"),
110	            new PermissionSeed("community.write", "Post or comment in the community", "community"),
111	            new PermissionSeed("moderation.review", "Review moderation reports", "community"),
112	            new PermissionSeed("notifications.read", "View own notifications", "notifications"),
113	            // Phase 7
114	            new PermissionSeed("credentials.review", "Review credential submissions", "credentials"),
115	            new PermissionSeed("risk.read", "View risk flags and incident log", "risk"),
116	            new PermissionSeed("risk.write", "Raise or clear risk flags", "risk"),
