124	    /**
125	     * Initial role definitions: code → (display name, permission codes).
126	     */
127	    /**
128	     * Every role gets a curated permission set. The seeder never removes permissions
129	     * from existing roles on restart, so admins can grant extra permissions through
130	     * the UI (future phase) without having them stripped on the next boot.
131	     */
132	    private static final List<RoleSeed> SEED_ROLES = List.of(
133	            new RoleSeed("ADMIN", "Administrator", Set.of(
