173	    private static final String SAMPLE_ORG_CODE = "HQ";
174	    private static final String SAMPLE_DEPT_CODE = "MAIN";
175	    private static final String SAMPLE_FACILITY_CODE = "DOJO-1";
176	
177	    private final BootstrapProperties props;
178	    private final UserRepository userRepository;
179	    private final RoleRepository roleRepository;
180	    private final PermissionRepository permissionRepository;
181	    private final ResourceRepository resourceRepository;
182	    private final OrganizationRepository organizationRepository;
183	    private final DepartmentRepository departmentRepository;
