189	    public DataSeeder(BootstrapProperties props,
190	                      UserRepository userRepository,
191	                      RoleRepository roleRepository,
192	                      PermissionRepository permissionRepository,
193	                      ResourceRepository resourceRepository,
194	                      OrganizationRepository organizationRepository,
195	                      DepartmentRepository departmentRepository,
196	                      FacilityAreaRepository facilityAreaRepository,
197	                      DataScopeRuleRepository dataScopeRuleRepository,
198	                      PasswordEncoder passwordEncoder,
199	                      AuditService auditService) {
200	        this.props = props;
201	        this.userRepository = userRepository;
202	        this.roleRepository = roleRepository;
203	        this.permissionRepository = permissionRepository;
204	        this.resourceRepository = resourceRepository;
205	        this.organizationRepository = organizationRepository;
206	        this.departmentRepository = departmentRepository;
207	        this.facilityAreaRepository = facilityAreaRepository;
208	        this.dataScopeRuleRepository = dataScopeRuleRepository;
209	        this.passwordEncoder = passwordEncoder;
