213	    @EventListener(ApplicationReadyEvent.class)
214	    @Transactional
215	    public void seed() {
216	        if (!props.isSeedOnStart()) {
217	            log.info("[seed] dojostay.bootstrap.seed-on-start=false — skipping");
218	            return;
219	        }
220	        seedResources();
221	        seedPermissions();
222	        seedRoles();
223	        SampleOrg sample = seedSampleOrg();
224	        seedAdmin();
225	        seedSampleStaff(sample);
226	    }
227	
228	    private void seedResources() {
229	        SEED_RESOURCES.forEach((code, label) -> resourceRepository.findByCode(code).orElseGet(() -> {
230	            Resource r = new Resource();
231	            r.setCode(code);
232	            r.setDisplayName(label);
233	            Resource saved = resourceRepository.save(r);
234	            log.info("[seed] resource created: {}", code);
235	            return saved;
236	        }));
237	    }
238	
239	    private void seedPermissions() {
240	        for (PermissionSeed seed : SEED_PERMISSIONS) {
241	            Permission p = permissionRepository.findByCode(seed.code()).orElseGet(() -> {
242	                Permission fresh = new Permission();
243	                fresh.setCode(seed.code());
244	                fresh.setDisplayName(seed.displayName());
245	                fresh.setResourceCode(seed.resourceCode());
246	                Permission saved = permissionRepository.save(fresh);
247	                log.info("[seed] permission created: {}", seed.code());
248	                return saved;
249	            });
250	            // Backfill resource_code for permissions that existed before Phase 2.
251	            if (p.getResourceCode() == null && seed.resourceCode() != null) {
252	                p.setResourceCode(seed.resourceCode());
253	                permissionRepository.save(p);
254	            }
255	        }
256	    }
257	
258	    private void seedRoles() {
259	        for (RoleSeed seed : SEED_ROLES) {
260	            Role role = roleRepository.findByCode(seed.code()).orElseGet(() -> {
261	                Role r = new Role();
262	                r.setCode(seed.code());
263	                r.setDisplayName(seed.displayName());
264	                return roleRepository.save(r);
265	            });
266	            // Reconcile permissions: only add missing ones, never remove (so manual
267	            // admin changes via the UI in later phases are preserved across restarts).
268	            Set<Permission> current = role.getPermissions();
269	            for (String permCode : seed.permissionCodes()) {
270	                boolean alreadyPresent = current.stream().anyMatch(p -> p.getCode().equals(permCode));
271	                if (!alreadyPresent) {
272	                    permissionRepository.findByCode(permCode).ifPresent(current::add);
273	                }
274	            }
275	            roleRepository.save(role);
276	        }
277	    }
278	
279	    private SampleOrg seedSampleOrg() {
280	        Organization org = organizationRepository.findByCode(SAMPLE_ORG_CODE).orElseGet(() -> {
281	            Organization o = new Organization();
282	            o.setCode(SAMPLE_ORG_CODE);
283	            o.setName("DojoStay HQ");
284	            o.setActive(true);
285	            Organization saved = organizationRepository.save(o);
286	            log.info("[seed] organization created: {}", SAMPLE_ORG_CODE);
287	            return saved;
288	        });
289	
290	        Department dept = departmentRepository.findByOrganizationId(org.getId()).stream()
291	                .filter(d -> SAMPLE_DEPT_CODE.equals(d.getCode()))
292	                .findFirst()
293	                .orElseGet(() -> {
294	                    Department d = new Department();
295	                    d.setOrganizationId(org.getId());
296	                    d.setCode(SAMPLE_DEPT_CODE);
297	                    d.setName("Main Hall");
298	                    d.setActive(true);
299	                    Department saved = departmentRepository.save(d);
300	                    log.info("[seed] department created: {}/{}", SAMPLE_ORG_CODE, SAMPLE_DEPT_CODE);
301	                    return saved;
302	                });
303	
304	        FacilityArea facility = facilityAreaRepository.findByOrganizationId(org.getId()).stream()
305	                .filter(f -> SAMPLE_FACILITY_CODE.equals(f.getCode()))
306	                .findFirst()
307	                .orElseGet(() -> {
308	                    FacilityArea f = new FacilityArea();
309	                    f.setOrganizationId(org.getId());
310	                    f.setDepartmentId(dept.getId());
311	                    f.setCode(SAMPLE_FACILITY_CODE);
312	                    f.setName("Primary Dojo");
313	                    f.setActive(true);
314	                    FacilityArea saved = facilityAreaRepository.save(f);
315	                    log.info("[seed] facility area created: {}/{}/{}",
316	                            SAMPLE_ORG_CODE, SAMPLE_DEPT_CODE, SAMPLE_FACILITY_CODE);
317	                    return saved;
318	                });
319	
320	        return new SampleOrg(org, dept, facility);
321	    }
322	
323	    private void seedAdmin() {
324	        if (props.getAdminPassword() == null || props.getAdminPassword().isBlank()) {
325	            log.warn("[seed] dojostay.bootstrap.admin-password is not set — admin user NOT created");
326	            return;
327	        }
328	        if (userRepository.existsByUsername(props.getAdminUsername())) {
329	            return;
330	        }
331	        Role adminRole = roleRepository.findByCode("ADMIN").orElseThrow();
332	        User admin = new User();
333	        admin.setUsername(props.getAdminUsername());
334	        admin.setFullName("Default Administrator");
335	        admin.setPasswordHash(passwordEncoder.encode(props.getAdminPassword()));
336	        admin.setPrimaryRole(UserRoleType.ADMIN);
337	        admin.setEnabled(true);
338	        admin.setRoles(new HashSet<>(Set.of(adminRole)));
339	        userRepository.save(admin);
340	        log.info("[seed] default admin user created: {}", props.getAdminUsername());
341	
342	        auditService.record(
343	                AuditAction.USER_CREATED,
344	                null,
345	                "system",
346	                "USER",
347	                String.valueOf(admin.getId()),
348	                "Default admin created by bootstrap seeder",
349	                null
350	        );
351	    }
352	
353	    /**
354	     * Creates a dev-only staff user scoped to the sample organization so Phase 2
355	     * data-scope filtering can be exercised locally. Only runs when the sample
356	     * staff password is configured (normally only in {@code application-dev.yml}).
357	     */
358	    private void seedSampleStaff(SampleOrg sample) {
359	        if (props.getSampleStaffPassword() == null || props.getSampleStaffPassword().isBlank()) {
360	            return;
361	        }
362	        if (userRepository.existsByUsername(props.getSampleStaffUsername())) {
363	            return;
364	        }
365	        Role staffRole = roleRepository.findByCode("STAFF").orElseThrow();
366	        User staff = new User();
367	        staff.setUsername(props.getSampleStaffUsername());
368	        staff.setFullName("Sample HQ Staff");
369	        staff.setPasswordHash(passwordEncoder.encode(props.getSampleStaffPassword()));
370	        staff.setPrimaryRole(UserRoleType.STAFF);
371	        staff.setOrganizationId(sample.organization().getId());
372	        staff.setEnabled(true);
373	        staff.setRoles(new HashSet<>(Set.of(staffRole)));
374	        User saved = userRepository.save(staff);
375	
376	        DataScopeRule rule = new DataScopeRule();
377	        rule.setUserId(saved.getId());
378	        rule.setScopeType(FacilityScopeType.ORGANIZATION);
379	        rule.setScopeTargetId(sample.organization().getId());
380	        dataScopeRuleRepository.save(rule);
381	
382	        log.info("[seed] sample staff user created: {} scoped to org {}",
383	                props.getSampleStaffUsername(), SAMPLE_ORG_CODE);
384	
385	        auditService.record(
386	                AuditAction.USER_CREATED,
387	                null,
388	                "system",
389	                "USER",
390	                String.valueOf(saved.getId()),
391	                "Sample staff user created by bootstrap seeder",
392	                null
393	        );
394	        auditService.record(
395	                AuditAction.DATA_SCOPE_CHANGED,
396	                null,
397	                "system",
398	                "USER",
399	                String.valueOf(saved.getId()),
400	                "Sample staff scoped to organization " + SAMPLE_ORG_CODE,
401	                null
402	        );
403	    }
404	
405	    private record PermissionSeed(String code, String displayName, String resourceCode) {
406	    }
407	
408	    private record RoleSeed(String code, String displayName, Set<String> permissionCodes) {
409	    }
410	
411	    private record SampleOrg(Organization organization, Department department, FacilityArea facility) {
412	    }
413	}
