108	    @Transactional
109	    public PostResponse createPost(CreatePostRequest req, String sourceIp) {
110	        EffectiveScope scope = dataScopeService.forCurrentUser();
111	        if (!scope.fullAccess() && !scope.hasOrganization(req.organizationId())) {
112	            throw new BusinessException("OUT_OF_SCOPE",
113	                    "Cannot post in an organization outside your data scope",
114	                    HttpStatus.FORBIDDEN);
115	        }
116	        Long actor = requireActor();
117	        Post p = new Post();
118	        p.setOrganizationId(req.organizationId());
119	        p.setAuthorUserId(actor);
120	        p.setTitle(req.title());
121	        p.setBody(req.body());
122	        p.setVisibility(req.visibility() != null ? req.visibility() : Post.Visibility.ORGANIZATION);
123	        p.setStatus(Post.Status.PUBLISHED);
124	        Post saved = postRepository.save(p);
125	
126	        auditService.record(AuditAction.POST_CREATED, actor, actorUsername(),
127	                "POST", String.valueOf(saved.getId()),
128	                "Post created in org " + saved.getOrganizationId(), sourceIp);
129	
130	        // Mention resolution on post body (title is only advisory)
131	        deliverMentions(req.body(), saved.getId(), null, saved.getOrganizationId(),
132	                actor, "POST", String.valueOf(saved.getId()), sourceIp);
133	        return toResponse(saved);
134	    }
