148	    @Transactional
149	    public CommentResponse createComment(CreateCommentRequest req, String sourceIp) {
150	        Post p = loadReadableOrThrow(req.postId());
151	        if (p.getStatus() != Post.Status.PUBLISHED) {
152	            throw new BusinessException("POST_NOT_OPEN",
153	                    "Post is not accepting comments", HttpStatus.CONFLICT);
154	        }
155	        Long actor = requireActor();
156	
157	        // Validate reply/quote targets live on the same post — prevents
158	        // cross-thread smuggling of a quoted comment.
159	        if (req.parentCommentId() != null) {
160	            PostComment parent = commentRepository.findById(req.parentCommentId())
161	                    .orElseThrow(() -> new NotFoundException("Parent comment not found"));
162	            if (!parent.getPostId().equals(p.getId())) {
163	                throw new BusinessException("INVALID_PARENT",
164	                        "Parent comment does not belong to this post",
165	                        HttpStatus.BAD_REQUEST);
166	            }
167	        }
168	        if (req.quotedCommentId() != null) {
169	            PostComment quoted = commentRepository.findById(req.quotedCommentId())
170	                    .orElseThrow(() -> new NotFoundException("Quoted comment not found"));
171	            if (!quoted.getPostId().equals(p.getId())) {
172	                throw new BusinessException("INVALID_QUOTE",
173	                        "Quoted comment does not belong to this post",
174	                        HttpStatus.BAD_REQUEST);
175	            }
176	        }
177	
178	        PostComment c = new PostComment();
179	        c.setPostId(p.getId());
180	        c.setOrganizationId(p.getOrganizationId());
181	        c.setAuthorUserId(actor);
182	        c.setBody(req.body());
183	        c.setParentCommentId(req.parentCommentId());
184	        c.setQuotedCommentId(req.quotedCommentId());
185	        c.setStatus(PostComment.Status.PUBLISHED);
186	        PostComment saved = commentRepository.save(c);
187	
188	        auditService.record(AuditAction.COMMENT_CREATED, actor, actorUsername(),
189	                "COMMENT", String.valueOf(saved.getId()),
190	                "Comment on post " + p.getId(), sourceIp);
191	
192	        // Reply notification — goes to the parent comment's author (not the
193	        // post owner, which would spam them for every deep reply).
194	        if (req.parentCommentId() != null) {
195	            commentRepository.findById(req.parentCommentId()).ifPresent(parent -> {
196	                if (!parent.getAuthorUserId().equals(actor)
197	                        && canNotify(parent.getAuthorUserId(), actor, p.getId())) {
198	                    notificationService.deliver(parent.getAuthorUserId(), p.getOrganizationId(),
199	                            "COMMENT_REPLY", "New reply",
200	                            "Someone replied to your comment",
201	                            "COMMENT", String.valueOf(saved.getId()), sourceIp);
202	                }
203	            });
204	        } else if (!p.getAuthorUserId().equals(actor)
205	                && canNotify(p.getAuthorUserId(), actor, p.getId())) {
206	            // Top-level comment → notify the post author
207	            notificationService.deliver(p.getAuthorUserId(), p.getOrganizationId(),
208	                    "POST_COMMENT", "New comment",
209	                    "Someone commented on your post",
210	                    "COMMENT", String.valueOf(saved.getId()), sourceIp);
211	        }
212	
213	        // Mention notifications
214	        deliverMentions(req.body(), null, saved.getId(), p.getOrganizationId(),
215	                actor, "COMMENT", String.valueOf(saved.getId()), sourceIp);
216	        return toResponse(saved);
217	    }
