234	                            "POST", String.valueOf(p.getId()),
235	                            "Post liked", sourceIp);
236	                    if (!p.getAuthorUserId().equals(actor)
237	                            && canNotify(p.getAuthorUserId(), actor, p.getId())) {
238	                        notificationService.deliver(p.getAuthorUserId(), p.getOrganizationId(),
239	                                "POST_LIKE", "New like",
240	                                "Someone liked your post",
241	                                "POST", String.valueOf(p.getId()), sourceIp);
242	                    }
243	                    return saved;
244	                });
245	        long count = likeRepository.countByPostId(p.getId());
246	        return new LikeStatusResponse(p.getId(), null, count, true);
247	    }
