483	    private PostComment loadReadableCommentOrThrow(Long commentId) {
484	        PostComment c = commentRepository.findById(commentId)
485	                .orElseThrow(() -> new NotFoundException("Comment not found"));
486	        Post p = postRepository.findById(c.getPostId())
487	                .orElseThrow(() -> new NotFoundException("Comment not found"));
488	        EffectiveScope scope = dataScopeService.forCurrentUser();
489	        if (!canRead(p, scope)) {
490	            throw new NotFoundException("Comment not found");
491	        }
492	        return c;
493	    }
494	
495	    private boolean canRead(Post p, EffectiveScope scope) {
496	        if (scope.fullAccess()) return true;
497	        if (p.getVisibility() == Post.Visibility.PUBLIC) return true;
498	        return scope.hasOrganization(p.getOrganizationId());
499	    }
500	
501	    private Set<Long> loadBlockedUserIds(Long actor) {
502	        return blockRepository.findByUserIdOrderByIdDesc(actor).stream()
503	                .map(UserBlock::getBlockedUserId)
504	                .collect(Collectors.toCollection(HashSet::new));
505	    }
506	
507	    /**
508	     * Notification gating. Skips delivery when:
509	     * <ul>
510	     *   <li>the recipient has muted this thread, or</li>
511	     *   <li>the recipient has blocked the actor (hide existence)</li>
512	     * </ul>
513	     */
514	    private boolean canNotify(Long recipientUserId, Long actorUserId, Long postId) {
515	        if (postId != null && muteRepository.existsByUserIdAndPostId(recipientUserId, postId)) {
516	            return false;
517	        }
518	        if (blockRepository.existsByUserIdAndBlockedUserId(recipientUserId, actorUserId)) {
519	            return false;
520	        }
521	        return true;
522	    }
523	
524	    /**
525	     * Parse {@code @username} mentions out of free text, resolve them against
526	     * {@link UserRepository}, insert {@link PostMention} rows, and fire
527	     * MENTION notifications. Unknown usernames are silently dropped.
528	     */
529	    private void deliverMentions(String body, Long postId, Long commentId, Long organizationId,
530	                                 Long actor, String refType, String refId, String sourceIp) {
531	        if (body == null || body.isEmpty()) return;
532	        Matcher m = MENTION_PATTERN.matcher(body);
533	        Set<String> seen = new HashSet<>();
534	        List<PostMention> mentions = new ArrayList<>();
535	        while (m.find()) {
536	            String username = m.group(1);
537	            if (!seen.add(username.toLowerCase())) continue;
538	            Optional<User> target = userRepository.findByUsername(username);
539	            if (target.isEmpty()) continue;
540	            Long recipient = target.get().getId();
541	            if (recipient.equals(actor)) continue; // self-mentions are noise
542	
543	            PostMention pm = new PostMention();
544	            pm.setPostId(postId);
545	            pm.setCommentId(commentId);
546	            pm.setMentionedUserId(recipient);
547	            mentions.add(pm);
548	
549	            if (canNotify(recipient, actor, postId != null ? postId
550	                    : (commentId != null ? resolvePostIdForComment(commentId) : null))) {
551	                notificationService.deliver(recipient, organizationId,
552	                        "MENTION", "You were mentioned",
553	                        "Someone mentioned you in a " + refType.toLowerCase(java.util.Locale.ROOT),
554	                        refType, refId, sourceIp);
555	            }
556	        }
557	        if (!mentions.isEmpty()) {
558	            mentionRepository.saveAll(mentions);
559	        }
560	    }
561	
562	    private Long resolvePostIdForComment(Long commentId) {
563	        return commentRepository.findById(commentId).map(PostComment::getPostId).orElse(null);
564	    }
565	
566	    private static Long actorId() {
567	        return CurrentUserResolver.current().map(CurrentUser::id).orElse(null);
568	    }
569	
570	    private static String actorUsername() {
571	        return CurrentUserResolver.current().map(CurrentUser::username).orElse("system");
572	    }
573	
574	    private static Long requireActor() {
575	        Long id = actorId();
576	        if (id == null) {
577	            throw new BusinessException("NO_ACTOR",
578	                    "An authenticated user is required",
579	                    HttpStatus.UNAUTHORIZED);
580	        }
581	        return id;
582	    }
583	
584	    private static PostResponse toResponse(Post p) {
585	        return new PostResponse(
586	                p.getId(), p.getOrganizationId(), p.getAuthorUserId(),
587	                p.getTitle(), p.getBody(), p.getVisibility(), p.getStatus(),
588	                p.getHiddenReason(), p.getCreatedAt(), p.getUpdatedAt(),
589	                p.getHiddenAt(), p.getRestoredAt()
590	        );
591	    }
592	
593	    private static CommentResponse toResponse(PostComment c) {
594	        return new CommentResponse(
595	                c.getId(), c.getPostId(), c.getOrganizationId(),
596	                c.getAuthorUserId(), c.getBody(),
597	                c.getParentCommentId(), c.getQuotedCommentId(),
598	                c.getStatus(), c.getHiddenReason(),
599	                c.getCreatedAt(), c.getHiddenAt(), c.getRestoredAt()
600	        );
601	    }
602	}
