9	import org.springframework.stereotype.Service;
10	import org.springframework.transaction.annotation.Transactional;
11	
12	import java.util.List;
13	
14	/**
15	 * Feature toggle registry. Toggles are a global, admin-managed concept — they
16	 * have no org scope, so there's no {@code DataScopeSpec} filtering here.
17	 * Mutations are audited with {@link AuditAction#FEATURE_TOGGLE_CHANGED}.
18	 */
19	@Service
20	public class FeatureToggleService {
21	
22	    private final FeatureToggleRepository repository;
23	    private final AuditService auditService;
24	
25	    public FeatureToggleService(FeatureToggleRepository repository,
26	                                AuditService auditService) {
27	        this.repository = repository;
28	        this.auditService = auditService;
29	    }
30	
31	    @Transactional(readOnly = true)
32	    public List<FeatureToggleResponse> list() {
33	        return repository.findAll().stream()
34	                .map(FeatureToggleService::toResponse)
35	                .toList();
36	    }
37	
38	    @Transactional
39	    public FeatureToggleResponse upsert(UpsertFeatureToggleRequest req, String sourceIp) {
40	        FeatureToggle t = repository.findByCode(req.code()).orElseGet(FeatureToggle::new);
41	        boolean isNew = t.getId() == null;
42	        boolean prev = t.isEnabled();
43	        t.setCode(req.code());
44	        t.setDescription(req.description());
45	        t.setEnabled(Boolean.TRUE.equals(req.enabled()));
46	        t.setUpdatedByUserId(actorId());
47	        FeatureToggle saved = repository.save(t);
48	
49	        if (isNew || prev != saved.isEnabled()) {
50	            auditService.record(AuditAction.FEATURE_TOGGLE_CHANGED, actorId(), actorUsername(),
51	                    "FEATURE_TOGGLE", saved.getCode(),
52	                    (isNew ? "Created " : "Changed ")
53	                            + saved.getCode() + " enabled=" + saved.isEnabled(),
54	                    sourceIp);
55	        }
56	        return toResponse(saved);
57	    }
58	
59	    /** Best-effort enabled check used by other services. Falls back to false. */
60	    @Transactional(readOnly = true)
61	    public boolean isEnabled(String code) {
62	        return repository.findByCode(code).map(FeatureToggle::isEnabled).orElse(false);
63	    }
64	
65	    private static Long actorId() {
66	        return CurrentUserResolver.current().map(CurrentUser::id).orElse(null);
67	    }
68	
69	    private static String actorUsername() {
70	        return CurrentUserResolver.current().map(CurrentUser::username).orElse("system");
71	    }
72	
73	    private static FeatureToggleResponse toResponse(FeatureToggle t) {
74	        return new FeatureToggleResponse(
75	                t.getId(), t.getCode(), t.getDescription(),
76	                t.isEnabled(), t.getUpdatedAt(), t.getUpdatedByUserId()
77	        );
78	    }
79	}
