18	
19	import java.util.List;
20	
21	@RestController
22	@RequestMapping("/api/bookings")
23	public class BookingController {
24	
25	    private final BookingService bookingService;
26	
27	    public BookingController(BookingService bookingService) {
28	        this.bookingService = bookingService;
29	    }
30	
31	    @GetMapping
32	    @PreAuthorize("hasAuthority('bookings.read')")
33	    public ApiResponse<List<BookingResponse>> list(
34	            @RequestParam(required = false) Long sessionId,
35	            @RequestParam(required = false) Long studentId) {
36	        if (sessionId != null) {
37	            return ApiResponse.ok(bookingService.listForSession(sessionId));
38	        }
39	        if (studentId != null) {
40	            return ApiResponse.ok(bookingService.listForStudent(studentId));
41	        }
42	        return ApiResponse.ok(List.of());
43	    }
44	
45	    @PostMapping
46	    @PreAuthorize("hasAuthority('bookings.write')")
47	    public ApiResponse<BookingResponse> book(@Valid @RequestBody CreateBookingRequest req,
48	                                             HttpServletRequest httpReq) {
49	        return ApiResponse.ok(bookingService.book(req, clientIp(httpReq)));
50	    }
51	
52	    /**
53	     * INITIATED → CONFIRMED transition. Separate endpoint rather than a
54	     * generic status-PATCH so Spring Security can gate it distinctly if we
55	     * later split the confirm permission from the plain write permission.
56	     */
57	    @PostMapping("/{id}/confirm")
58	    @PreAuthorize("hasAuthority('bookings.write')")
59	    public ApiResponse<BookingResponse> confirm(@PathVariable Long id,
60	                                                HttpServletRequest httpReq) {
61	        return ApiResponse.ok(bookingService.confirm(id, clientIp(httpReq)));
62	    }
63	
64	    @DeleteMapping("/{id}")
65	    @PreAuthorize("hasAuthority('bookings.write')")
66	    public ApiResponse<BookingResponse> cancel(@PathVariable Long id,
67	                                               HttpServletRequest httpReq) {
68	        return ApiResponse.ok(bookingService.cancel(id, clientIp(httpReq)));
69	    }
70	
71	    /**
72	     * Post a credit-ledger refund for a cancelled booking and move it to
73	     * REFUNDED. Refunds are ALWAYS internal credit — never cash — so the
74	     * request body only carries the credit amount and an optional note.
75	     */
76	    @PostMapping("/{id}/refund")
77	    @PreAuthorize("hasAuthority('bookings.write')")
78	    public ApiResponse<BookingResponse> refund(@PathVariable Long id,
79	                                               @Valid @RequestBody RefundBookingRequest req,
80	                                               HttpServletRequest httpReq) {
81	        return ApiResponse.ok(bookingService.refund(
82	                id, req.creditAmount(), req.notes(), clientIp(httpReq)));
83	    }
84	
85	    private static String clientIp(HttpServletRequest req) {
86	        String xff = req.getHeader("X-Forwarded-For");
87	        if (xff != null && !xff.isBlank()) {
88	            int comma = xff.indexOf(',');
89	            return comma > 0 ? xff.substring(0, comma).trim() : xff.trim();
90	        }
91	        return req.getRemoteAddr();
92	    }
93	}
