2	
3	import com.dojostay.audit.AuditAction;
4	import com.dojostay.audit.AuditService;
5	import com.dojostay.auth.CurrentUser;
6	import com.dojostay.auth.CurrentUserResolver;
7	import com.dojostay.ops.dto.BackupStatusResponse;
8	import com.dojostay.ops.dto.RecordBackupRequest;
9	import org.springframework.stereotype.Service;
10	import org.springframework.transaction.annotation.Transactional;
11	
12	import java.util.List;
13	
14	/**
15	 * Records the outcome of backup jobs. This service does not perform backups
16	 * itself — it is a logbook that the out-of-process backup tool calls into via
17	 * the ops API to leave a breadcrumb trail that ops users can review.
18	 */
19	@Service
20	public class BackupStatusService {
21	
22	    private final BackupStatusRepository repository;
23	    private final AuditService auditService;
24	
25	    public BackupStatusService(BackupStatusRepository repository,
26	                               AuditService auditService) {
27	        this.repository = repository;
28	        this.auditService = auditService;
29	    }
30	
31	    @Transactional(readOnly = true)
32	    public List<BackupStatusResponse> listRecent() {
33	        return repository.findTop20ByOrderByStartedAtDesc().stream()
34	                .map(BackupStatusService::toResponse)
35	                .toList();
36	    }
37	
38	    @Transactional
39	    public BackupStatusResponse record(RecordBackupRequest req, String sourceIp) {
40	        BackupStatus b = new BackupStatus();
41	        b.setKind(req.kind());
42	        b.setStatus(req.status());
43	        b.setStartedAt(req.startedAt());
44	        b.setCompletedAt(req.completedAt());
45	        b.setLocation(req.location());
46	        b.setSizeBytes(req.sizeBytes());
47	        b.setDurationMs(req.durationMs());
48	        b.setNotes(req.notes());
49	        BackupStatus saved = repository.save(b);
50	
51	        auditService.record(AuditAction.BACKUP_RECORDED, actorId(), actorUsername(),
52	                "BACKUP", String.valueOf(saved.getId()),
53	                req.kind() + " status=" + req.status(),
54	                sourceIp);
55	        return toResponse(saved);
56	    }
57	
58	    private static Long actorId() {
59	        return CurrentUserResolver.current().map(CurrentUser::id).orElse(null);
60	    }
61	
62	    private static String actorUsername() {
63	        return CurrentUserResolver.current().map(CurrentUser::username).orElse("system");
64	    }
65	
66	    private static BackupStatusResponse toResponse(BackupStatus b) {
67	        return new BackupStatusResponse(
68	                b.getId(), b.getKind(), b.getStatus(),
69	                b.getLocation(), b.getSizeBytes(), b.getDurationMs(),
70	                b.getNotes(), b.getStartedAt(), b.getCompletedAt()
71	        );
72	    }
73	}
