59	    private static final Set<Booking.Status> CANCELABLE =
60	            EnumSet.of(Booking.Status.INITIATED, Booking.Status.CONFIRMED,
61	                    Booking.Status.BOOKED, Booking.Status.CHECKED_IN);
62	
63	    /** Terminal states that release the seat. */
64	    private static final Set<Booking.Status> SEAT_RELEASED =
65	            EnumSet.of(Booking.Status.CANCELED, Booking.Status.CANCELLED,
66	                    Booking.Status.REFUNDED, Booking.Status.NO_SHOW);
67	
