105	    @Transactional
106	    public BookingResponse book(CreateBookingRequest req, String sourceIp) {
107	        TrainingSession session = loadAccessibleSession(req.trainingSessionId());
108	        Student student = loadAccessibleStudent(req.studentId());
109	
110	        if (!session.getOrganizationId().equals(student.getOrganizationId())) {
111	            throw new BusinessException("ORG_MISMATCH",
112	                    "Student and training session belong to different organizations",
113	                    HttpStatus.BAD_REQUEST);
114	        }
115	        if (session.getStatus() == TrainingSession.Status.CANCELLED) {
116	            throw new BusinessException("SESSION_CANCELLED",
117	                    "Session has been cancelled and cannot accept bookings",
118	                    HttpStatus.CONFLICT);
119	        }
120	        long booked = bookingRepository.countActiveBookingsForSession(session.getId());
121	        if (booked >= session.getCapacity()) {
122	            throw new BusinessException("SESSION_FULL",
123	                    "Session has no remaining seats",
124	                    HttpStatus.CONFLICT);
125	        }
126	        List<Booking> conflicts = bookingRepository.findConflictingBookings(
127	                student.getId(), session.getStartsAt(), session.getEndsAt());
128	        if (!conflicts.isEmpty()) {
129	            throw new BusinessException("BOOKING_CONFLICT",
130	                    "Student already has an overlapping booking",
131	                    HttpStatus.CONFLICT);
132	        }
133	
134	        Booking b = new Booking();
135	        b.setTrainingSessionId(session.getId());
136	        b.setStudentId(student.getId());
137	        b.setOrganizationId(session.getOrganizationId());
138	        b.setStatus(Booking.Status.INITIATED);
139	        // Copy session type onto the booking so reporting / client views don't
140	        // need a second JOIN just to tell a venue booking from an online one.
141	        if (session.getSessionType() != null) {
142	            b.setSessionType(Booking.SessionType.valueOf(session.getSessionType().name()));
143	        }
144	        b.setNotes(req.notes());
145	        b.setCreatedByUserId(actorId() != null ? actorId() : 0L);
146	        Booking saved = bookingRepository.save(b);
147	
148	        auditService.record(AuditAction.BOOKING_CREATED, actorId(), actorUsername(),
149	                "BOOKING", String.valueOf(saved.getId()),
150	                "Student " + student.getId() + " initiated booking on session " + session.getId(),
151	                sourceIp);
152	        return toResponse(saved);
153	    }
154	
155	    /**
156	     * Move an {@code INITIATED} booking to {@code CONFIRMED}. No-op for rows
157	     * that are already confirmed. Rejects any other origin state so the
158	     * state machine cannot be bypassed.
159	     */
160	    @Transactional
161	    public BookingResponse confirm(Long bookingId, String sourceIp) {
162	        Booking b = loadAccessibleBooking(bookingId);
163	        if (b.getStatus() == Booking.Status.CONFIRMED) {
164	            return toResponse(b);
165	        }
166	        if (b.getStatus() != Booking.Status.INITIATED) {
167	            throw new BusinessException("INVALID_TRANSITION",
168	                    "Only INITIATED bookings can be confirmed (current=" + b.getStatus() + ")",
169	                    HttpStatus.CONFLICT);
170	        }
171	        b.setStatus(Booking.Status.CONFIRMED);
172	        Booking saved = bookingRepository.save(b);
173	        auditService.record(AuditAction.BOOKING_CREATED, actorId(), actorUsername(),
174	                "BOOKING", String.valueOf(saved.getId()),
175	                "Booking confirmed", sourceIp);
176	        return toResponse(saved);
177	    }
178	
179	    /**
180	     * Cancel a booking. Idempotent for already-terminal rows. The status
181	     * written depends on the origin row: legacy rows preserve the old
182	     * {@code CANCELLED} spelling so history stays consistent; B6 rows use
183	     * the new {@code CANCELED} spelling.
184	     */
185	    @Transactional
186	    public BookingResponse cancel(Long bookingId, String sourceIp) {
187	        Booking b = loadAccessibleBooking(bookingId);
188	        if (SEAT_RELEASED.contains(b.getStatus())) {
189	            return toResponse(b);
190	        }
191	        if (!CANCELABLE.contains(b.getStatus())) {
192	            throw new BusinessException("INVALID_TRANSITION",
193	                    "Booking in state " + b.getStatus() + " cannot be cancelled",
194	                    HttpStatus.CONFLICT);
195	        }
196	        Booking.Status target = (b.getStatus() == Booking.Status.INITIATED
197	                || b.getStatus() == Booking.Status.CONFIRMED)
198	                ? Booking.Status.CANCELED
199	                : Booking.Status.CANCELLED;
200	        b.setStatus(target);
201	        b.setCancelledAt(Instant.now());
202	        Booking saved = bookingRepository.save(b);
203	        auditService.record(AuditAction.BOOKING_CANCELLED, actorId(), actorUsername(),
204	                "BOOKING", String.valueOf(saved.getId()),
205	                "Booking cancelled -> " + target, sourceIp);
206	        return toResponse(saved);
207	    }
208	
209	    /**
210	     * Post an internal-credit refund for a cancelled booking and move it to
211	     * {@code REFUNDED}. Refunds are NEVER cash — the ledger delta is positive
212	     * credit posted via {@link CreditService#adjust}. The booking stores the
213	     * resulting ledger tx id so audit can trace the refund back.
214	     *
215	     * @param creditAmount positive number of credits to refund
216	     */
217	    @Transactional
218	    public BookingResponse refund(Long bookingId, int creditAmount, String notes, String sourceIp) {
219	        if (creditAmount <= 0) {
220	            throw new BusinessException("INVALID_REFUND_AMOUNT",
221	                    "Refund amount must be a positive number of credits",
222	                    HttpStatus.BAD_REQUEST);
223	        }
224	        Booking b = loadAccessibleBooking(bookingId);
225	        if (b.getStatus() == Booking.Status.REFUNDED) {
226	            return toResponse(b);
227	        }
228	        if (b.getStatus() != Booking.Status.CANCELED && b.getStatus() != Booking.Status.CANCELLED) {
229	            throw new BusinessException("INVALID_TRANSITION",
230	                    "Only cancelled bookings can be refunded (current=" + b.getStatus() + ")",
231	                    HttpStatus.CONFLICT);
232	        }
233	        if (b.getRefundCreditTxId() != null) {
234	            throw new BusinessException("ALREADY_REFUNDED",
235	                    "Booking already has a refund ledger entry",
236	                    HttpStatus.CONFLICT);
237	        }
238	
239	        CreditTransactionResponse tx = creditService.adjust(new CreditAdjustmentRequest(
240	                b.getStudentId(),
241	                creditAmount,
242	                "BOOKING_REFUND",
243	                "BOOKING",
244	                String.valueOf(b.getId()),
245	                notes
246	        ), sourceIp);
247	
248	        b.setStatus(Booking.Status.REFUNDED);
249	        b.setRefundCreditTxId(tx.id());
250	        Booking saved = bookingRepository.save(b);
251	        auditService.record(AuditAction.BOOKING_CANCELLED, actorId(), actorUsername(),
252	                "BOOKING", String.valueOf(saved.getId()),
253	                "Booking refunded -> credit tx " + tx.id() + " amount=" + creditAmount,
254	                sourceIp);
255	        return toResponse(saved);
256	    }
257	
258	    private Booking loadAccessibleBooking(Long bookingId) {
259	        Booking b = bookingRepository.findById(bookingId)
260	                .orElseThrow(() -> new NotFoundException("Booking not found"));
261	        EffectiveScope scope = dataScopeService.forCurrentUser();
262	        if (!scope.fullAccess() && !scope.hasOrganization(b.getOrganizationId())) {
263	            throw new NotFoundException("Booking not found");
264	        }
265	        return b;
266	    }
