271	        EffectiveScope scope = dataScopeService.forCurrentUser();
272	        if (!scope.fullAccess() && !scope.hasOrganization(s.getOrganizationId())) {
273	            throw new NotFoundException("Training session not found");
274	        }
275	        return s;
276	    }
