281	        EffectiveScope scope = dataScopeService.forCurrentUser();
282	        if (!scope.fullAccess() && !scope.hasOrganization(s.getOrganizationId())) {
283	            throw new NotFoundException("Student not found");
284	        }
285	        return s;
