288	    private static BookingResponse toResponse(Booking b) {
289	        return new BookingResponse(
290	                b.getId(), b.getTrainingSessionId(), b.getStudentId(),
291	                b.getOrganizationId(), b.getStatus(), b.getSessionType(),
292	                b.getRefundCreditTxId(), b.getNotes(),
