93	router.beforeEach(async (
94	  to: RouteLocationNormalized,
95	  _from: RouteLocationNormalized,
96	  next: NavigationGuardNext,
97	) => {
98	  const auth = useAuthStore();
99	  if (!auth.initialized) {
100	    await auth.refresh();
101	  }
102	
103	  const requiresAuth = to.matched.some((r) => r.meta.requiresAuth);
104	  if (requiresAuth && !auth.isAuthenticated) {
105	    return next({ name: 'login', query: { redirect: to.fullPath } });
106	  }
107	  if (to.name === 'login' && auth.isAuthenticated) {
108	    return next({ name: 'dashboard' });
109	  }
110	
111	  // Role-based gating: if a route declares allowed roles, the current user's
112	  // primary role must be in that list. This is a UX guard — the backend remains
113	  // the source of truth via @PreAuthorize / SecurityConfig.
114	  const allowedRoles = to.meta.roles;
115	  if (allowedRoles && allowedRoles.length > 0 && auth.primaryRole) {
116	    if (!allowedRoles.includes(auth.primaryRole)) {
117	      return next({ name: 'dashboard' });
118	    }
119	  }
120	  return next();
121	});
