200	                new InputStreamReader(csvInput, StandardCharsets.UTF_8))) {
201	            String headerLine = reader.readLine();
202	            if (headerLine == null || headerLine.isBlank()) {
203	                throw new BusinessException("EMPTY_CSV", "CSV input is empty", HttpStatus.BAD_REQUEST);
