222	                    }
223	                    String externalId = cell(fields, cols, "externalId");
224	                    if (externalId != null && !externalId.isBlank()
225	                            && studentRepository
226	                                    .findByOrganizationIdAndExternalId(organizationId, externalId)
227	                                    .isPresent()) {
228	                        skipped++;
229	                        continue;
230	                    }
231	
232	                    Student s = new Student();
233	                    s.setOrganizationId(organizationId);
234	                    s.setExternalId(externalId);
235	                    s.setFullName(fullName);
236	                    s.setEmail(cell(fields, cols, "email"));
237	                    s.setPhone(cell(fields, cols, "phone"));
238	                    s.setSkillLevel(cell(fields, cols, "skillLevel"));
239	                    s.setSchool(cell(fields, cols, "school"));
240	                    s.setProgram(cell(fields, cols, "program"));
241	                    s.setClassGroup(cell(fields, cols, "classGroup"));
242	                    s.setHousingAssignment(cell(fields, cols, "housingAssignment"));
243	                    s.setEnrollmentStatus(EnrollmentStatus.PROSPECT);
244	                    studentRepository.save(s);
245	                    created++;
246	                } catch (RuntimeException ex) {
247	                    failed++;
248	                    recordError(sample, allErrors, lineNumber, "ROW_FAILED", ex.getMessage());
249	                }
250	            }
251	        } catch (IOException ioe) {
252	            throw new BusinessException("CSV_READ_FAILED",
253	                    "Could not read CSV: " + ioe.getMessage(), HttpStatus.BAD_REQUEST);
254	        }
255	
256	        String reportPath = null;
257	        if (!allErrors.isEmpty()) {
258	            reportPath = writeErrorReport(job.getId(), allErrors);
259	        }
260	
261	        job.setTotalRows(total);
262	        job.setCreatedRows(created);
263	        job.setSkippedRows(skipped);
264	        job.setFailedRows(failed);
265	        job.setStatus(BulkImportJob.Status.COMPLETED);
266	        job.setCompletedAt(Instant.now());
267	        if (!allErrors.isEmpty()) {
268	            job.setErrorSummary(allErrors.size() + " row errors (see error report)");
269	            job.setErrorReportPath(reportPath);
270	        }
271	        BulkImportJob saved = jobRepository.save(job);
272	
273	        auditService.record(AuditAction.BULK_IMPORT_RUN, actorId(), actorUsername(),
274	                "BULK_IMPORT_JOB", String.valueOf(saved.getId()),
275	                "Students import: created=" + created + " skipped=" + skipped
276	                        + " failed=" + failed, sourceIp);
277	
278	        return new BulkImportResult(saved.getId(), total, created, skipped, failed, sample, reportPath);
279	    }
