292	    /**
293	     * Read the persisted error report for a finished import job, enforcing the
294	     * scope filter. Returns the CSV bytes or throws 404 if the job has no
295	     * errors or is not accessible to the caller.
296	     */
297	    @Transactional(readOnly = true)
298	    public byte[] readErrorReport(Long jobId) {
299	        BulkImportJob job = jobRepository.findById(jobId)
300	                .orElseThrow(() -> new NotFoundException("Import job not found"));
301	        EffectiveScope scope = dataScopeService.forCurrentUser();
302	        if (!scope.fullAccess()
303	                && (job.getOrganizationId() == null
304	                        || !scope.hasOrganization(job.getOrganizationId()))) {
305	            throw new NotFoundException("Import job not found");
306	        }
307	        if (job.getErrorReportPath() == null) {
308	            throw new NotFoundException("Import job has no error report");
309	        }
310	        try {
311	            return Files.readAllBytes(Paths.get(job.getErrorReportPath()));
312	        } catch (IOException ioe) {
313	            throw new BusinessException("REPORT_READ_FAILED",
314	                    "Could not read error report: " + ioe.getMessage(),
315	                    HttpStatus.INTERNAL_SERVER_ERROR);
316	        }
317	    }
