319	    private static void recordError(List<BulkImportResult.RowError> sample,
320	                                    List<BulkImportResult.RowError> all,
321	                                    int lineNumber, String code, String message) {
322	        BulkImportResult.RowError err = new BulkImportResult.RowError(lineNumber, code, message);
323	        all.add(err);
324	        if (sample.size() < MAX_SAMPLE_ERRORS) {
325	            sample.add(err);
326	        }
327	    }
