329	    /**
330	     * Write the full error list to a CSV file under the tmpdir and return its
331	     * absolute path. Uses the job id in the filename so concurrent imports do
332	     * not clobber each other's reports.
333	     */
334	    private static String writeErrorReport(Long jobId, List<BulkImportResult.RowError> errors) {
335	        try {
336	            Path root = Paths.get(System.getProperty("java.io.tmpdir"), "dojostay-import-errors");
337	            Files.createDirectories(root);
338	            String fname = "student-import-" + jobId + "-"
339	                    + REPORT_STAMP.format(Instant.now()) + ".csv";
340	            Path target = root.resolve(fname);
341	            StringBuilder sb = new StringBuilder("lineNumber,code,message\n");
342	            for (BulkImportResult.RowError e : errors) {
343	                sb.append(e.lineNumber()).append(',')
344	                        .append(csvEscape(e.code())).append(',')
345	                        .append(csvEscape(e.message())).append('\n');
346	            }
347	            Files.writeString(target, sb.toString(), StandardCharsets.UTF_8);
348	            return target.toAbsolutePath().toString();
349	        } catch (IOException ioe) {
350	            // Do not fail the whole import because we couldn't spool the error report —
351	            // the caller still receives the sample errors in the API response.
352	            return null;
353	        }
354	    }
