356	    private static String csvEscape(String v) {
357	        if (v == null) return "";
358	        boolean needsQuote = v.indexOf(',') >= 0 || v.indexOf('"') >= 0 || v.indexOf('\n') >= 0;
359	        String escaped = v.replace("\"", "\"\"");
360	        return needsQuote ? "\"" + escaped + "\"" : escaped;
361	    }
