393	    private static void requireColumn(Map<String, Integer> cols, String name) {
394	        if (!cols.containsKey(name)) {
395	            throw new BusinessException("MISSING_COLUMN",
396	                    "CSV is missing required column: " + name, HttpStatus.BAD_REQUEST);
397	        }
