400	    private static String cell(String[] fields, Map<String, Integer> cols, String name) {
401	        Integer idx = cols.get(name);
402	        if (idx == null || idx >= fields.length) return null;
403	        String v = fields[idx];
404	        if (v == null) return null;
405	        v = v.trim();
406	        return v.isEmpty() ? null : v;
407	    }
