409	    /** Minimal CSV splitter supporting double-quoted fields with embedded commas. */
410	    private static String[] splitCsv(String line) {
411	        List<String> out = new ArrayList<>();
412	        StringBuilder cur = new StringBuilder();
413	        boolean inQuotes = false;
414	        for (int i = 0; i < line.length(); i++) {
415	            char c = line.charAt(i);
416	            if (inQuotes) {
417	                if (c == '"') {
418	                    if (i + 1 < line.length() && line.charAt(i + 1) == '"') {
419	                        cur.append('"');
420	                        i++;
421	                    } else {
422	                        inQuotes = false;
423	                    }
424	                } else {
425	                    cur.append(c);
426	                }
427	            } else if (c == ',') {
428	                out.add(cur.toString());
429	                cur.setLength(0);
430	            } else if (c == '"' && cur.length() == 0) {
431	                inQuotes = true;
432	            } else {
433	                cur.append(c);
434	            }
435	        }
436	        out.add(cur.toString());
437	        return out.toArray(new String[0]);
438	    }
