460	            phone = DataMasking.maskPhone(phone);
461	            externalId = DataMasking.maskId(externalId);
462	            ec = DataMasking.maskPhone(ec);
463	        }
464	        return new StudentResponse(
465	                s.getId(),
466	                s.getUserId(),
467	                s.getOrganizationId(),
468	                externalId,
469	                s.getFullName(),
470	                email,
471	                phone,
