3	import java.util.Set;
4	
5	/**
6	 * Immutable snapshot of what a given user is allowed to see, decomposed by scope axis.
7	 *
8	 * <ul>
9	 *   <li>{@code fullAccess == true} → the user bypasses data scope filtering entirely
10	 *       (typically because they hold the ADMIN role).</li>
11	 *   <li>Otherwise the three sets are the union of scope target ids the user has access
12	 *       to at each axis. An empty set at a given axis means "no access at this axis".</li>
13	 * </ul>
14	 */
15	public record EffectiveScope(
16	        boolean fullAccess,
17	        Set<Long> organizationIds,
18	        Set<Long> departmentIds,
19	        Set<Long> facilityAreaIds
20	) {
21	
22	    public static EffectiveScope fullAccess() {
23	        return new EffectiveScope(true, Set.of(), Set.of(), Set.of());
24	    }
25	
26	    public static EffectiveScope empty() {
27	        return new EffectiveScope(false, Set.of(), Set.of(), Set.of());
28	    }
29	
30	    public boolean hasOrganization(Long orgId) {
31	        return fullAccess || (orgId != null && organizationIds.contains(orgId));
32	    }
33	
34	    public boolean hasDepartment(Long deptId) {
35	        return fullAccess || (deptId != null && departmentIds.contains(deptId));
36	    }
37	
38	    public boolean hasFacilityArea(Long areaId) {
39	        return fullAccess || (areaId != null && facilityAreaIds.contains(areaId));
40	    }
41	
42	    public boolean hasAnyOrganization() {
43	        return fullAccess || !organizationIds.isEmpty();
44	    }
45	}
