5	/**
6	 * Standard response envelope for all DojoStay API endpoints.
7	 *
8	 * <p>Either {@code data} is populated (success) or {@code error} is populated (failure).
9	 * The {@code traceId} field carries the per-request correlation id so clients can quote it
10	 * when reporting issues.
11	 */
12	@JsonInclude(JsonInclude.Include.NON_NULL)
13	public record ApiResponse<T>(
14	        boolean success,
15	        T data,
16	        ApiError error,
17	        String traceId
18	) {
19	
20	    public static <T> ApiResponse<T> ok(T data, String traceId) {
21	        return new ApiResponse<>(true, data, null, traceId);
22	    }
23	
24	    public static <T> ApiResponse<T> ok(T data) {
25	        return ok(data, CorrelationIdHolder.get());
26	    }
27	
28	    public static ApiResponse<Void> empty() {
29	        return new ApiResponse<>(true, null, null, CorrelationIdHolder.get());
30	    }
31	
32	    public static <T> ApiResponse<T> failure(ApiError error, String traceId) {
33	        return new ApiResponse<>(false, null, error, traceId);
34	    }
35	
36	    public static <T> ApiResponse<T> failure(ApiError error) {
37	        return failure(error, CorrelationIdHolder.get());
38	    }
39	}
