          </span>
        </div>
        <p v-if="s.notes" class="desc">{{ s.notes }}</p>
        <div class="meta">
          <div><strong>When:</strong> {{ formatDate(s.startsAt) }} – {{ formatDate(s.endsAt) }}</div>
