              <button v-if="b.status === 'INITIATED' || b.status === 'CONFIRMED'" type="button" @click="cancelBooking(b.id)" class="btn-sm btn-danger">Cancel</button>
            </td>
          </tr>
        </tbody>
      </table>
    </div>
  </section>
